args.sparql:
SELECT ?attendance WHERE {
  ?game wdt:P31 wd:Q8287658 ;
        wdt:P641 ?homeTeam ;
        wdt:P645 ?awayTeam ;
        wdt:P2545 ?attendance ;
        wdt:P161 ?series .
  ?series wdt:P31 wd:Q1363275 .
  FILTER ( ( ?homeTeam = wd:Q334634 && ?awayTeam = wd:Q650840 ) ||
           ( ?homeTeam = wd:Q650840 && ?awayTeam = wd:Q334634 ) )
}
ORDER BY DESC(?attendance)
LIMIT 1

